        'terms_general_2' => 'Sähköpostimme: <a href="mailto:info@floventus.com">info@floventus.com</a>',
        'terms_general_3' => 'Verkkosivusto sisältää tietoa kolmansien osapuolten alustoista ("Kolmannen Osapuolen Alustat"), erityisesti koulutuksellisia palveluita yleisistä sijoitustekniikoista tai markkinatutkimuksesta. Floventra toimii välittäjänä, yhdistämällä käyttäjät näihin Kolmannen Osapuolen Alustoihin ("Palvelut").',
        'terms_general_4' => 'Nämä käyttöehdot ("Ehdot") säätelevät sinun ("Sinä", "Sinun" tai "Käyttäjä") käyttöä Verkkosivustolla ja Palveluissa. Nämä Ehdot tulee lukea huolellisesti kokonaisuudessaan ennen Palveluiden käyttöä. Huomaa, että nämä Ehdot muodostavat laillisesti sitovan sopimuksen sinun ja Verkkosivuston operaattorin Floventran, <a href="mailto:info@floventus.com">info@floventus.com</a>, välillä. Jos et ole samaa mieltä jonkin näiden Ehtojen kohdan kanssa, sinun tulee välittömästi lopettaa Verkkosivuston käyttö. Käyttämällä Verkkosivustoa hyväksyt Ehdot sellaisina kuin ne on aika ajoin muutettu.',
        'terms_general_5' => 'Nämä Ehdot sisältävät Tietosuojakäytäntömme, ja hyväksymällä nämä Ehdot vahvistat, että hyväksyt ja suostut myös Tietosuojakäytäntöömme (voit tarkastella Tietosuojakäytäntöämme <a href="/fi/privacy-policy/">klikkaamalla tästä</a>).',
        'terms_services_title' => '2. Palveluiden kuvaus',
        'terms_services_1' => 'Emme ole sijoitusalusta, emmekä yhdistä sinua sellaisiin alustoihin, paitsi jos tällainen alusta sitoutuu tarjoamaan sinulle vain koulutuksellisia palveluita tai markkinatutkimusta.',
        'terms_services_2' => 'Toimimme välittäjänä yhdistääksemme sinut palveluntarjoajaan, joka voi tarjota koulutuksellista sisältöä yleisistä sijoitustekniikoista tai markkinatutkimuksesta kiinnostuksesi kohteisiin, noudattaen Finanssivalvonnan määräyksiä Suomessa.',
        'terms_services_3' => 'Edellä mainitun palveluntarjoajan edustaja ottaa sinuun yhteyttä, kun olet rekisteröitynyt Verkkosivustollemme antamalla täydelliset ja oikeat tiedot.',
        'terms_services_4' => 'Edellä mainitun edustajan rooli kohdassa 2.3. on tarjota sinulle tietoa yleisistä sijoitustekniikoista, jotka vastaavat kiinnostuksen kohteitasi tai ovat tällä hetkellä suosittuja, ja parantaa ymmärrystäsi sijoitusstrategioista.',
        'terms_eligibility_title' => '3. Kelpoisuus',
        'terms_eligibility_1' => 'Olet oikeutettu käyttämään Verkkosivustoa ja hyötymään Palveluista vain, jos täytät seuraavat ehdot:',
        'terms_eligibility_2' => 'Olet vähintään 18-vuotias;',
        'terms_eligibility_3' => 'Sinulla on oikeus, valtuudet ja kapasiteetti solmia nämä Ehdot ja noudattaa kaikkia näiden Ehtojen ehtoja ja määräyksiä;',
        'terms_eligibility_4' => 'Et ole kielletty käyttämästä Verkkosivustoa ja/tai Palveluita Suomen tai sen maan lakien mukaisesti, jossa asut tai sijaitset käyttäessäsi Verkkosivustoa.',
        'terms_restricted_territories_title' => '4. Rajoitetut alueet',
        'terms_restricted_territories_1' => 'Rajoittamatta edellä mainittua yleisyyttä, voimme rajoittaa Verkkosivuston ja/tai Palveluiden (tai niiden osien) saatavuutta käyttäjille, jotka sijaitsevat alueilla, joissa oikeudellinen ja sääntelykehys on ristiriidassa Palveluiden tarjoamisen kanssa.',
        'terms_restricted_territories_2' => 'Voimme asettaa lisävaatimuksia tai ehtoja ennen kuin hyväksymme käyttäjiä, jotka asuvat tai ovat tietyistä maista, jos tämä on tarpeen Suomen tai käyttäjien asuinalueen lakien noudattamiseksi. Lisäksi tunnustetaan, että jos käyttäjät matkustavat rajoitetuille alueille, Verkkosivusto ja/tai Palvelut voivat olla siellä saatavilla tai estettyinä.',
        'terms_prohibited_activities_title' => '5. Kielletyt toiminnot',
        'terms_prohibited_activities_1' => 'Sitoudut käyttämään Verkkosivustoa ja Palveluita kunnioittavasti, ja sitoudut olemaan:',
        'terms_prohibited_activities_2' => 'Linkittämättä Verkkosivustoon ja/tai käyttämättä Verkkosivustoa lataamiseen, jakamiseen, julkaisemiseen tai siirtämiseen (a) tietoa tai muuta materiaalia tavalla, joka rikkoo oikeuksia, mukaan lukien immateriaalioikeudet, yksityisyyden suojan oikeudet tai muut oikeudet; (b) tietoa tai muuta materiaalia, joka on kielletty julkaisemasta tai käyttämästä, koska se sisältää uhkauksia, vahinkoa, loukkauksia, herjauksia, rasismia tai sopimatonta sisältöä; (c) tietoa tai muuta materiaalia, joka sisältää viruksen tai muun ohjelmiston, joka voi vahingoittaa tietokonejärjestelmiämme tai kolmansia osapuolia tai rajoittaa tai estää muita käyttämästä Verkkosivustoa; (d) tietoa tai muuta materiaalia, joka rikkoo lakia; tai (e) tietoa tai muuta materiaalia, joka sisältää minkäänlaista mainontaa ilman etukäteen antamaamme kirjallista lupaa;',
        'terms_prohibited_activities_3' => 'Poistamasta tai muuttamasta mitään attribuutteja, oikeudellisia ilmoituksia tai muita omistusoikeudellisia merkintöjä tai tarroja Verkkosivustolla;',
        'terms_prohibited_activities_4' => 'Käyttämästä Palveluita muun käyttöliittymän kautta kuin Verkkosivuston;',
        'terms_prohibited_activities_5' => 'Häiritsemästä muiden käyttäjien Verkkosivuston ja/tai Palveluiden käyttöä;',
        'terms_prohibited_activities_6' => 'Käyttämästä botteja tai muita automaattisia menetelmiä Verkkosivuston ja/tai Palveluiden käyttöön tai pääsyyn;',
        'terms_prohibited_activities_7' => 'Lataamasta tai siirtämästä (tai yrittämästä ladata tai siirtää), ilman nimenomaista lupaamme, materiaalia, joka toimii passiivisena tai aktiivisena tiedonkeruu- tai siirtomekanismina, mukaan lukien, mutta ei rajoittuen, web-bugeihin, evästeisiin tai muihin vastaaviin vakoiluohjelmiin;',
        'terms_prohibited_activities_8' => 'Osallistumasta <b>"kehystämiseen", "peilaamiseen"</b> tai muuten simuloimasta Palveluiden ulkoasua tai toimintaa;',
        'terms_prohibited_activities_9' => 'Rikkomasta sovellettavia lakeja tai määräyksiä, rohkaisemasta tai edistämästä mitään laitonta toimintaa, mukaan lukien, mutta ei rajoittuen, tekijänoikeusrikkomuksiin, tavaramerkkirikkomuksiin, herjauksiin, yksityisyyden loukkauksiin, identiteettivarkauksiin, hakkerointiin, krakkamiseen tai väärennettyjen ohjelmistojen jakeluun;',
        'terms_prohibited_activities_10' => 'Tekemästä muutoksia ja/tai puuttumasta millään tavalla Verkkosivuston lähdekoodiin ja lataamasta ohjelmistoja ja/tai sovelluksia, jotka voivat vahingoittaa Verkkosivustoa tai kolmatta osapuolta;',
        'terms_prohibited_activities_11' => 'Purkamasta, kääntämästä taaksepäin tai muuten käänteistekniikalla selvittämästä mitään Verkkosivustolla olevaa ohjelmistoa tai muuta teknologiaa, jota käytetään Palveluiden tarjoamiseen.',
        'terms_prohibited_activities_12' => 'Tunnustat, että ilman ennakkoluuloja muille oikeuksille, joita meillä voi olla, jos huomaamme, että Verkkosivuston käyttösi ei ole näiden Ehtojen tai sovellettavan lain mukaista, voimme estää pääsysi Verkkosivustolle ja/tai Palveluihin.',
        'terms_intellectual_property_title' => '6. Immateriaalioikeudet',
        'terms_intellectual_property_1' => 'Verkkosivusto ja sen sisältö, mukaan lukien videomateriaalit, teksti, valokuvat, logot, mallit, musiikki, ääni, kuviot, tavaramerkit ja muu Verkkosivustolla oleva sisältö, ovat suojattuja meidän tai kolmannen osapuolen immateriaalioikeuksilla.',
        'terms_intellectual_property_2' => 'Meidän ja Käyttäjän välillä me säilytämme kaikki oikeudet, omistuksen ja intressit Verkkosivustoon ja Palveluihin. Verkkosivuston ja/tai Palveluiden käyttö ei anna Käyttäjälle mitään immateriaalioikeuksia, jotka sisältyvät Verkkosivustoon ja/tai Palveluihin, paitsi oikeuden käyttää Verkkosivustoa ja/tai Palveluita näiden Ehtojen mukaisesti.',
        'terms_intellectual_property_3' => 'Käyttäjä voi käyttää Verkkosivustoa ja/tai Palveluita vain henkilökohtaiseen ja ei-kaupalliseen käyttöön.',
        'terms_intellectual_property_4' => 'Et saa, etkä saa sallia muiden osapuolten muokata, purkaa, kääntää taaksepäin, kopioida, siirtää, luoda johdannaisteoksia, vuokrata, alilisensoida, jakaa, jäljentää kehystettynä, julkaista uudelleen, kaapia, ladata, näyttää, siirtää, lähettää, vuokrata tai myydä missään muodossa tai millään tavalla, kokonaan tai osittain, käyttää mihinkään muuhun tarkoitukseen kuin Verkkosivuston tai Palveluiden käyttöön näiden Ehtojen mukaisesti tai muuten hyödyntää Verkkosivuston sisältöä ilman nimenomaista, etukäteen annettua kirjallista lupaamme.',
        'terms_liability_title' => '7. Vastuunrajoitus',
        'terms_liability_1' => 'Emme voi olla vastuussa menetyksistä tai vahingoista, jotka johtuvat näiden Ehtojen täyttämättä jättämisestä tai virheellisestä täyttämisestä, joka on seurausta (i) Sinusta, (ii) kolmannen osapuolen ennakoimattomasta ja voittamattomasta teosta sopimukseen nähden tai (iii) ylivoimaisesta esteestä.',
        'terms_liability_2' => 'Mikään näissä ehdoissa ei ole tarkoitettu sulkemaan pois tai rajoittamaan vastuutamme sinulle, jos se olisi lainvastaista, erityisesti tapauksissa:',
        'terms_liability_3' => '(i) Kuolema tai henkilövahinko, joka johtuu huolimattomuudestamme,',
        'terms_liability_4' => '(ii) Petos tai petollinen väärä esitys, ja',
        'terms_liability_5' => '(iii) mikä tahansa muu vastuu, jota ei voida sulkea pois tai rajoittaa Suomen lain mukaan.',
        'terms_liability_6' => 'Rajoittamatta edellä mainittua yleisyyttä, emme ota vastuuta tai vastuuta mistään bugeista, viruksista, troijalaisista tai vastaavista, jotka voidaan siirtää Verkkosivustolle tai Palveluiden kautta kolmannen osapuolen toimesta, ellei se ole meidän syytämme.',
        'terms_liability_7' => 'Käytämme parhaamme varmistaaksemme, että Verkkosivusto on vapaa virheistä, erehdyksistä tai epätarkkuuksista sisällössä. Jos tällaisia virheitä, erehdyksiä tai epätarkkuuksia esiintyy, korjaamme ne viipymättä.',
        'terms_liability_8' => 'Suostut pitämään meidät vahingoittumattomina kaikista menetyksistä, jotka aiheutuvat kolmannelle osapuolelle Verkkosivustoon ja/tai Palveluihin liittyen, jotka johtuvat siitä, että rikot näitä Ehtoja.',
        'terms_liability_9' => 'Emme ole vastuussa mistään ongelmista tai teknisistä toimintahäiriöistä puhelin- tai verkkoyhteyksissä, tietokoneen online-järjestelmissä, palvelimissa tai tarjoajissa, laitteistoissa, ohjelmistoissa, teknisistä ongelmista johtuvista vioista tai internetin ruuhkautumisesta (tai internetin saavuttamattomuudesta) tai Verkkosivuston tai Palveluiden ja selaimesi ja/tai muiden laitteiden yhteensopimattomuudesta. Rajoittamatta edellä mainittua yleisyyttä, emme ota mitään vastuuta tai riskiä internetin käytöstäsi.',
        'terms_third_party_title' => '8. Kolmannen osapuolen palvelut tai sisältö',
        'terms_third_party_1' => 'Käyttäessäsi Palveluita voit nähdä kolmansien osapuolten tarjoamaa sisältöä tai palveluita, mukaan lukien mainoksia ja arvosteluja Kolmannen Osapuolen Alustoista.',
        'terms_third_party_2' => 'Emme hallitse, tue tai ota käyttöön tällaista sisältöä tai palveluita, eivätkä ne välttämättä aina ole tarkkoja tai ajankohtaisia.',
        'terms_third_party_3' => 'Suosittelemme, että tarkistat itsenäisesti kaikki tiedot ennen kuin luotat niihin, ja kaikki päätökset tai toimet, jotka perustuvat tällaisiin tietoihin, ovat yksinomaan sinun vastuullasi.',
        'terms_links_title' => '9. Linkit',
        'terms_links_1' => 'Verkkosivusto voi sisältää linkkejä, sisältöä, mainoksia, tarjouksia, logoja ja muita materiaaleja muilta verkkosivustoilta tai ohjelmistoista, joita kolmannet osapuolet hallitsevat tai tarjoavat ("Linkit"). Kehotamme sinua varmistamaan, että ymmärrät riskit, jotka liittyvät tällaisten verkkosivustojen, ohjelmistojen tai materiaalien käyttöön ennen kuin haet, käytät, luotat tai ostat mitään näiden verkkosivustojen tai ohjelmistojen kautta tai niiden materiaalien perusteella. Tällaiset Linkit tarjotaan yksinomaan sinun mukavuudeksesi, ja suostut siihen, että et missään olosuhteissa pidä meitä vastuussa mistään menetyksistä tai vahingoista, jotka aiheutuvat muiden verkkosivustojen sisällön, tavaroiden tai palveluiden käytöstä tai niihin luottamisesta.',
        'terms_links_2' => 'Linkkien sisällyttäminen Verkkosivustolle ei ole hyväksyntä, valtuutus, sponsorointi, affiliaatio tai muu yhteys meidän ja näiden verkkosivustojen, ohjelmistojen tai niiden operaattoreiden välillä.',
        'terms_links_3' => 'Emme ole tarkastaneet mitään tai kaikkia tällaisia Linkkejä emmekä ole vastuussa minkään niiden kautta viitattujen verkkosivustojen tai ohjelmistojen sisällöstä. Kehotamme sinua varmistamaan, että ymmärrät riskit, jotka liittyvät tällaisten verkkosivustojen tai ohjelmistojen käyttöön ennen kuin haet, käytät, luotat tai ostat mitään näiden verkkosivustojen tai ohjelmistojen kautta. Et missään olosuhteissa pidä meitä vastuussa mistään menetyksistä tai vahingoista, jotka aiheutuvat muiden verkkosivustojen sisällön, tavaroiden tai palveluiden käytöstä tai niihin luottamisesta.',
        'terms_links_4' => 'On sinun vastuullasi tarkistaa tällaisten kolmansien osapuolten verkkosivustojen ehdot ja käytännöt, ja suosittelemme vahvasti, että tarkistat ne huolellisesti ennen kuin sitoudut tällaisiin kolmansiin osapuoliin.',
        'terms_miscellaneous_title' => '10. Sekalaista',
        'terms_miscellaneous_1' => 'Voimme muuttaa, muokata tai lopettaa aika ajoin minkä tahansa Palveluiden osan ja/tai esitellä uusia Palveluita tulevaisuutta varten.',
        'terms_miscellaneous_2' => 'Voimme muuttaa näitä Ehtoja aika ajoin. Kun teemme niin, ilmoitamme sinulle julkaisemalla uusimman version ja päivittämällä tämän sivun yläosassa olevan päivämäärän, ja kaikki muutokset astuvat voimaan välittömästi tällaisen julkaisun jälkeen. Jatkamalla Verkkosivuston käyttöä muutosten voimaantulon jälkeen katsotaan, että hyväksyt muutetut Ehdot.',
        'terms_miscellaneous_3' => 'Käyttäjä suostuu siihen, että tiedon siirto Verkkosivustolle tai sieltä pois ei luo mitään suhdetta, joka poikkeaisi näissä Ehdoissa määritellyistä.',
        'terms_miscellaneous_4' => 'Nämä Ehdot ja Tietosuojakäytäntö, sellaisina kuin niitä aika ajoin muutetaan, muodostavat ainoat pätevät sopimukset meidän ja Käyttäjän välillä, eikä mikään esitys, lupaus, suostumus tai sitoumus, olipa se kirjallinen tai suullinen, jota ei sisälly Ehtoihin tai Tietosuojakäytäntöön, sido osapuolia.',
        'terms_miscellaneous_5' => 'Mikään epäonnistuminen tai viivästys meidän puoleltamme minkään oikeuden, vallan tai korjaustoimenpiteen käytössä ei toimi sen luopumisena, eikä mikään yksittäinen tai osittainen tällaisen oikeuden, vallan tai korjaustoimenpiteen käyttö estä mitään muuta tai lisäkäyttöä siitä tai minkään muun oikeuden, vallan tai korjaustoimenpiteen käyttöä.',
        'terms_miscellaneous_6' => 'Jos jokin näiden Ehtojen määräys todetaan toimivaltaisen tuomioistuimen toimesta täytäntöönpanokelvottomaksi sovellettavan lain nojalla, kyseinen määräys suljetaan pois näistä Ehdoista, ja loput Ehdot tulkitaan ikään kuin kyseinen määräys olisi suljettu pois ja ovat täytäntöönpanokelpoisia niiden ehtojen mukaisesti; edellyttäen kuitenkin, että tällaisessa tapauksessa nämä Ehdot tulkitaan siten, että ne antavat vaikutuksen, suurimmassa mahdollisessa määrin sovellettavan lain mukaisesti, suljetun määräyksen merkitykseen ja tarkoitukseen, kuten toimivaltainen tuomioistuin on määrännyt.',
        'terms_miscellaneous_7' => 'Voimme siirtää tai luovuttaa kaikki oikeutemme ja velvollisuutemme tässä kolmannelle osapuolelle, edellyttäen, että tämä ei vaikuta negatiivisesti oikeuksiisi. Lisäksi, rajoittamatta edellä mainittua, Verkkosivustoa ja/tai mitä tahansa Palveluista voivat operoida kolmannet osapuolet. Et voi siirtää, luovuttaa tai pantata millään tavalla oikeuksiasi tai velvollisuuksiasi näiden Ehtojen nojalla.',
        'terms_miscellaneous_8' => 'Näitä ehtoja säätelee Suomen laki.',
        'terms_miscellaneous_9' => 'Kaikkien näistä Ehdoista johtuvien tai niiden yhteydessä olevien kiistojen yksinomainen tuomioistuinpaikka on Suomen tuomioistuimet.',

        'privacy_purpose_title' => 'Ilmoituksen tarkoitus',
        'privacy_purpose_text' => 'Tämän Tietosuoja-ilmoituksen ("Ilmoitus") tarkoitus on selittää, miten Floventra ("Floventra" tai "Me") käsittelee rekisterinpitäjänä henkilökohtaisia tietojasi, jotka annat meille vieraillessasi verkkosivustolla floventus.com ("Verkkosivusto"), tai jotka saamme kolmansilta osapuolilta, yhdistääksemme sinut ammattilaisiin, joista saatat olla kiinnostunut.',
        'privacy_data_categories_title' => 'Mitä henkilökohtaisia tietokategorioita käsitellään?',
        'privacy_data_categories_text' => 'Keräämme ja käsittelemme seuraavia henkilökohtaisia tietokategorioita sinusta:',
        'privacy_data_collection_title' => 'Kuinka tietosi kerätään?',
        'privacy_data_collection_text' => 'Keräämme henkilökohtaisia tietojasi:',
        'privacy_data_collection_direct' => 'Suoraan sinulta, kun annat tunnistetietosi Verkkosivustollamme; ja/tai',
        'privacy_data_collection_indirect' => 'Epäsuorasti:',
        'privacy_data_collection_indirect_1' => 'kun saamme tunnistetietojasi kolmansilta osapuolilta (mukaan lukien sijoituskoulutusyritykset, kumppanit / tytäryhtiöt / markkinoijat / digitaaliset toimistot); ja/tai',
        'privacy_data_collection_indirect_2' => 'kun keräämme tietoja Verkkosivustomme selaamiseen liittyen evästeiden tai vastaavien teknologioiden avulla (kuten määritelty Evästekäytännössä).',
        'privacy_data_collection_note' => 'Sinulla ei ole velvollisuutta antaa meille henkilökohtaisia tietojasi. Henkilökohtaisten tietojesi antamatta jättäminen estää meitä kuitenkin yhdistämästä sinua ammattilaisiin, joista saatat olla kiinnostunut.',
        'privacy_data_sharing_title' => 'Kenen kanssa henkilökohtaisia tietojani jaetaan?',
        'privacy_data_sharing_text' => 'Jaamme henkilökohtaisia tietojasi:',
        'privacy_data_sharing_1' => 'Ryhmämme sisällä;',
        'privacy_data_sharing_2' => 'Kumppaneidemme kanssa heidän omiin käsittelytarkoituksiinsa, mukaan lukien tarjotakseen sinulle tietoa palveluistaan ja/tai tuotteistaan, joista saatat olla kiinnostunut, edellyttäen, että annoit etukäteen suostumuksesi tällaiseen jakamiseen. Tällaisia kumppaneita ovat Finanssivalvonnan sääntelemät sijoituskoulutusyritykset, datavälittäjät ja välittäjät;',
        'privacy_data_sharing_3' => 'Kolmansien osapuolten kanssa, jotka tarjoavat meille palveluita, kuten tallennus- ja isännöintipalveluntarjoajat, analyyttiset, tekniset ja diagnostiset palvelut;',
        'privacy_data_sharing_4' => 'Neuvonantajillemme, erityisesti lakisääteisten velvoitteidemme noudattamiseksi, erityisesti kirjanpidon, tarkastuksen ja sisäisen valvonnan osalta;',
        'privacy_data_sharing_5' => 'Osana yrityksemme ja sen varojen kokonaan tai osittain myyntiä kolmannelle osapuolelle tai osana liiketoiminnan uudelleenjärjestelyä tai rakenneuudistusta (mukaan lukien purkaminen tai selvitystila); ja',
        'privacy_data_sharing_6' => 'Siellä, missä sovellettava laki vaatii tai sallii, viranomaisille, tuomioistuimille, ulkopuolisille neuvonantajille ja vastaaville kolmansille osapuolille.',
        'privacy_cross_border_title' => 'Rajojen ylittävät tiedonsiirrot',
        'privacy_cross_border_text_1' => 'Siirrämme henkilökohtaisia tietojasi Suomen ulkopuolelle. Jotkut vastaanottajat sijaitsevat maissa, joille Suomen hallitus on antanut riittävyyspäätöksen, kuten Israel. Siirto tunnustetaan näin ollen tarjoavan riittävän tietosuojan tason EU:n GDPR-näkökulmasta.',
        'privacy_cross_border_text_2' => 'Jotkut henkilökohtaisten tietojesi vastaanottajat voivat sijaita toisessa maassa, jolle Suomen hallitus ei ole antanut riittävyyspäätöstä.',
        'privacy_cross_border_text_3' => 'Solmimalla asianmukaisia tiedonsiirtosopimuksia, jotka perustuvat EU:n GDPR-standardisopimuslausekkeisiin tai muihin riittäviin keinoihin, olemme varmistaneet, että kaikki muut Suomen ulkopuolella sijaitsevat vastaanottajat tarjoavat riittävän tietosuojan tason henkilökohtaisille tiedoille ja että asianmukaiset tekniset ja organisatoriset turvatoimet ovat käytössä suojaamaan henkilökohtaisia tietoja vahingossa tapahtuvalta tai laittomalta tuhoamiselta, vahingossa tapahtuvalta menetykseltä tai muuttamiselta, luvattomalta paljastamiselta tai pääsyltä sekä kaikelta muulta laittomalta käsittelyltä. Kaikki jatkosiirrot (mukaan lukien tytäryhtiömme Suomen ulkopuolella) ovat alttiina asianmukaisille jatkosiirtovaatimuksille sovellettavan lain mukaisesti.',
        'privacy_retention_title' => 'Säilytys',
        'privacy_retention_text' => 'Säilytämme kerättyjä henkilökohtaisia tietoja vain niin kauan kuin on ehdottoman välttämätöntä tämän Ilmoituksen käsittelytarkoitusten saavuttamiseksi ja EU:n GDPR-asetuksen mukaisesti. Kun emme enää tarvitse henkilökohtaisia tietojasi, ne poistetaan ja/tai anonymisoidaan niin, että yksilöitä ei voida enää tunnistaa niistä (paitsi siltä osin kuin säilyttäminen on tarpeen lakisääteisten tai sääntelyvelvoitteiden noudattamiseksi tai oikeudellisten vaatimusten esittämiseksi tai puolustamiseksi).',
        'privacy_rights_title' => 'Oikeutesi',
        'privacy_rights_text' => 'EU:n GDPR-asetuksen nojalla sinulla on seuraavat oikeudet:',
        'privacy_right_access' => '<b>Pääsyoikeus:</b> Sinulla on oikeus saada meiltä vahvistus siitä, käsitelläänkö sinua koskevia henkilökohtaisia tietoja, ja jos näin on, pyytää pääsyä näihin henkilökohtaisiin tietoihin. Pääsytiedot sisältävät – muun muassa – käsittelyn tarkoitukset, asianomaisten henkilökohtaisten tietojen kategoriat sekä vastaanottajat tai vastaanottajien kategoriat, joille henkilökohtaisia tietoja on luovutettu tai tullaan luovuttamaan. Sinulla on oikeus saada kopio käsiteltävistä henkilökohtaisista tiedoista. Lisäkopioista, joita pyydät, voimme veloittaa kohtuullisen maksun hallinnollisten kustannusten perusteella.',
        'privacy_right_rectification' => '<b>Oikeus oikaisuun:</b> Sinulla on oikeus saada meiltä oikaisu sinua koskeviin epätarkkoihin henkilökohtaisiin tietoihin. Käsittelyn tarkoituksista riippuen sinulla on oikeus saada puutteelliset henkilökohtaiset tiedot täydennettyä, myös antamalla lisätietoja.',
        'privacy_right_erasure' => '<b>Oikeus poisto (oikeus tulla unohdetuksi):</b> Sinulla on oikeus pyytää meitä poistamaan henkilökohtaiset tietosi.',
        'privacy_right_restriction' => '<b>Oikeus käsittelyn rajoittamiseen:</b> Sinulla on oikeus pyytää henkilökohtaisten tietojesi käsittelyn rajoittamista. Tässä tapauksessa kyseiset tiedot merkitään, ja niitä voidaan käsitellä vain tiettyihin tarkoituksiin.',
        'privacy_right_portability' => '<b>Oikeus tietojen siirrettävyyteen:</b> Sinulla on oikeus saada sinua koskevat henkilökohtaiset tiedot, jotka olet antanut meille, jäsennellyssä, yleisesti käytetyssä ja koneellisesti luettavassa muodossa, ja sinulla on oikeus siirtää nämä henkilökohtaiset tiedot toiselle taholle ilman, että estämme tätä.',
        'privacy_right_object' => '<b>Oikeus vastustaa:</b> Sinulla on oikeus vastustaa, henkilökohtaiseen tilanteeseesi liittyvillä perusteilla, milloin tahansa henkilökohtaisten tietojesi käsittelyä meidän toimestamme, ja meitä voidaan vaatia lopettamaan henkilökohtaisten tietojesi käsittely. Jos sinulla on oikeus vastustaa ja käytät tätä oikeutta, henkilökohtaisia tietojasi ei enää käsitellä tällaisiin tarkoituksiin meidän toimestamme. Tämän oikeuden käyttäminen ei aiheuta kustannuksia. Tällaista vastustamisoikeutta ei välttämättä ole olemassa, erityisesti jos henkilökohtaisten tietojesi käsittely on välttämätöntä sopimuksen solmimista edeltävien toimenpiteiden suorittamiseksi tai jo solmitun sopimuksen täyttämiseksi.',
        'privacy_right_withdraw' => '<b>Oikeus peruuttaa suostumuksesi:</b> Jos henkilökohtaisten tietojesi käsittely perustuu suostumukseesi, sinulla on oikeus peruuttaa suostumuksesi milloin tahansa. Tällainen suostumuksen peruuttamisoikeus ei vaikuta aiemmin antamasi suostumuksen perusteella tapahtuneen käsittelyn laillisuuteen ennen peruuttamista.',
        'privacy_right_after_death' => '<b>Oikeus tietoihisi kuolemasi jälkeen:</b> Sinulla on oikeus antaa ohjeita, jotka liittyvät sinua koskevien henkilökohtaisten tietojen säilyttämiseen, poistamiseen ja välittämiseen kuolemasi jälkeen.',
        'privacy_rights_note' => 'Huomaa, että näitä oikeuksia voidaan rajoittaa sovellettavan Suomen tietosuojalain nojalla.',
        'privacy_rights_contact' => 'Jos haluat käyttää jotain näistä oikeuksista, ota meihin yhteyttä alla olevassa Ota yhteyttä -osiossa mainitulla tavalla.',
        'privacy_rights_complaint' => 'Sinulla on myös oikeus tehdä valitus Suomen toimivaltaiselle tietosuojaviranomaiselle, joka on Tietosuojavaltuutetun toimisto.',
        'privacy_contact_title' => 'Ota yhteyttä',
        'privacy_contact_text' => 'Henkilöillä, joilla on kysyttävää tästä Ilmoituksesta, tulee ottaa yhteyttä <a href="mailto:info@floventus.com">info@floventus.com</a>.',
        'privacy_changes_title' => 'Muutokset Tietosuoja-ilmoitukseen',
        'privacy_changes_text' => 'Tämä Tietosuoja-ilmoitus voi muuttua. Sinulle ilmoitetaan asianmukaisesti tällaisista muutoksista.',
        'privacy_last_updated' => 'Viimeksi päivitetty: 20.12.<script>document.write(new Date().getFullYear() - 2)</script>',
