        'terms_general_2' => 'আমাদের ইমেল: <a href="mailto:info@floventus.com">info@floventus.com</a>',
        'terms_general_3' => 'ওয়েবসাইটে তৃতীয় পক্ষের প্ল্যাটফর্ম (তৃতীয় পক্ষের প্ল্যাটফর্ম) সম্পর্কে তথ্য রয়েছে, যেমন সাধারণ বিনিয়োগ কৌশল বা বাজার গবেষণার শিক্ষাগত পরিষেবা। Floventra একটি মধ্যস্থতাকারী হিসেবে কাজ করে, ব্যবহারকারীদের এই তৃতীয় পক্ষের প্ল্যাটফর্মের সাথে সংযোগ করে (পরিষেবা)।',
        'terms_general_4' => 'এই ব্যবহারের শর্তাবলী (শর্তাবলী) আপনার (আপনি, আপনার বা ব্যবহারকারী) ওয়েবসাইট এবং পরিষেবার ব্যবহার নিয়ন্ত্রণ করে। পরিষেবা ব্যবহারের আগে আপনার এই শর্তাবলী সম্পূর্ণভাবে সাবধানে পড়া উচিত। দয়া করে মনে রাখবেন, এই শর্তাবলী আপনার এবং ওয়েবসাইটের অপারেটর Floventra, <a href="mailto:info@floventus.com">info@floventus.com</a> এর মধ্যে একটি আইনত বাধ্যতামূলক চুক্তি গঠন করে। আপনি যদি এই শর্তাবলীর কোনো বিধানের সাথে একমত না হন, তবে আপনি অবিলম্বে ওয়েবসাইট ব্যবহার বন্ধ করবেন। ওয়েবসাইট ব্যবহার করে, আপনি সময়ে সময়ে সংশোধিত শর্তাবলীতে সম্মত হন।',
        'terms_general_5' => 'এই শর্তাবলী আমাদের গোপনীয়তা নীতিকে অন্তর্ভুক্ত করে এবং এই শর্তাবলীতে সম্মত হওয়ার মাধ্যমে, আপনি নিশ্চিত করেন যে আপনি আমাদের গোপনীয়তা নীতিও গ্রহণ করেন এবং সম্মত হন (<a href="/bd/privacy-policy/">এখানে ক্লিক করে</a> আমাদের গোপনীয়তা নীতি পর্যালোচনা করতে পারেন)।',
        'terms_services_title' => '২. পরিষেবার বর্ণনা',
        'terms_services_1' => 'আমরা কোনো বিনিয়োগ প্ল্যাটফর্ম নই, এবং আমরা আপনাকে এমন কোনো বিনিয়োগ প্ল্যাটফর্মের সাথে সংযোগ করি না, যদি না এই প্ল্যাটফর্ম শুধুমাত্র শিক্ষাগত পরিষেবা বা বাজার গবেষণা প্রদানের প্রতিশ্রুতি দেয়।',
        'terms_services_2' => 'আমরা একটি মধ্যস্থতাকারী হিসেবে কাজ করি যাতে আপনাকে এমন একটি পরিষেবা প্রদানকারীর সাথে সংযোগ করা যায় যিনি আপনার আগ্রহের ক্ষেত্রে সাধারণ বিনিয়োগ কৌশল বা বাজার গবেষণার শিক্ষাগত বিষয়বস্তু প্রস্তাব করতে পারেন, যা বাংলাদেশে বিডিএসই নিয়মের সাথে সামঞ্জস্যপূর্ণ।',
        'terms_services_3' => 'উপরোক্ত পরিষেবা প্রদানকারীর একজন প্রতিনিধি আপনার সাথে যোগাযোগ করবেন যখন আপনি আমাদের ওয়েবসাইটে সম্পূর্ণ এবং সঠিক তথ্য প্রদান করে নিবন্ধন করবেন।',
        'terms_services_4' => '২.৩-এ উল্লিখিত প্রতিনিধির ভূমিকা হল আপনার আগ্রহের সাথে সামঞ্জস্যপূর্ণ বা বর্তমানে জনপ্রিয় সাধারণ বিনিয়োগ কৌশল সম্পর্কে তথ্য প্রদান করা এবং আপনার বিনিয়োগ কৌশল সম্পর্কে বোঝাপড়া উন্নত করা।',
        'terms_eligibility_title' => '৩. যোগ্যতা',
        'terms_eligibility_1' => 'আপনি কেবল তখনই ওয়েবসাইট ব্যবহার এবং পরিষেবার সুবিধা নিতে পারবেন, যদি আপনি নিম্নলিখিত সব শর্ত পূরণ করেন:',
        'terms_eligibility_2' => 'আপনার বয়স কমপক্ষে ১৮ বছর;',
        'terms_eligibility_3' => 'আপনার এই শর্তাবলীতে প্রবেশ করার এবং এর সমস্ত শর্ত ও বিধান মেনে চলার অধিকার, কর্তৃত্ব এবং ক্ষমতা রয়েছে;',
        'terms_eligibility_4' => 'আপনি বাংলাদেশ বা আপনি যে দেশে বসবাস করছেন বা ওয়েবসাইট ব্যবহার করার সময় অবস্থান করছেন সে দেশের আইন অনুসারে ওয়েবসাইট এবং/বা পরিষেবা ব্যবহার করতে নিষিদ্ধ নন।',
        'terms_restricted_territories_title' => '৪. নিষিদ্ধ অঞ্চল',
        'terms_restricted_territories_1' => 'উপরোক্ত সাধারণতার ব্যতিক্রম না করে, আমরা এমন অঞ্চলে অবস্থিত ব্যবহারকারীদের জন্য ওয়েবসাইট এবং/বা পরিষেবার (বা এর কোনো অংশ) উপলব্ধতা সীমিত করতে পারি যেখানে আইনি এবং নিয়ন্ত্রক কাঠামো পরিষেবা প্রদানের সাথে সামঞ্জস্যপূর্ণ নয়।',
        'terms_restricted_territories_2' => 'আমরা বাংলাদেশের আইন বা ব্যবহারকারী যে অঞ্চলে বসবাস করছেন সেখানকার আইন মেনে চলার জন্য নির্দিষ্ট দেশে বসবাসকারী ব্যবহারকারীদের গ্রহণের আগে অতিরিক্ত প্রয়োজনীয়তা বা শর্ত আরোপ করতে পারি। তদুপরি, এটি স্বীকৃত যে যদি কোনো ব্যবহারকারী নিষিদ্ধ অঞ্চলে ভ্রমণ করেন, তবে ওয়েবসাইট এবং/বা পরিষেবা সেখানে অনুপলব্ধ এবং/বা ব্লক করা হতে পারে।',
        'terms_prohibited_activities_title' => '৫. নিষিদ্ধ কার্যকলাপ',
        'terms_prohibited_activities_1' => 'আপনি ওয়েবসাইট এবং পরিষেবাগুলি সম্মানের সাথে ব্যবহার করার অঙ্গীকার করেন এবং নিম্নলিখিত কাজগুলি না করার অঙ্গীকার করেন:',
        'terms_prohibited_activities_2' => 'ওয়েবসাইটের সাথে লিঙ্ক করা এবং/বা ওয়েবসাইট ব্যবহার করা যাতে (ক) যে কোনো অধিকার লঙ্ঘন করে এমন তথ্য বা অন্যান্য উপাদান আপলোড, ডাউনলোড, বিতরণ, প্রকাশ বা প্রেরণ করা হয়, যার মধ্যে বুদ্ধিবৃত্তিক সম্পত্তি অধিকার, গোপনীয়তা সুরক্ষা অধিকার বা অন্য কোনো অধিকার অন্তর্ভুক্ত; (খ) প্রকাশ বা ব্যবহার নিষিদ্ধ তথ্য বা অন্যান্য উপাদান যা হুমকি, ক্ষতি, অপমান, মানহানি, অপবাদ, বর্ণবাদ বা অনুপযুক্ত বিষয়বস্তু গঠন করে; (গ) তথ্য বা অন্যান্য উপাদান যা ভাইরাস বা অন্যান্য সফটওয়্যার ধারণ করে যা আমাদের কম্পিউটার সিস্টেম বা তৃতীয় পক্ষের ক্ষতি করতে পারে বা অন্যদের ওয়েবসাইট ব্যবহারে সীমাবদ্ধ বা বাধা দিতে পারে; (ঘ) যে কোনো আইন লঙ্ঘন করে এমন তথ্য বা অন্যান্য উপাদান; বা (ঙ) আমাদের পূর্ব লিখিত অনুমতি ছাড়া যে কোনো ধরনের বিজ্ঞাপন ধারণ করে এমন তথ্য বা অন্যান্য উপাদান;',
        'terms_prohibited_activities_3' => 'ওয়েবসাইটে কোনো অ্যাট্রিবিউশন, আইনি নোটিশ বা অন্যান্য মালিকানাধীন উপাধি বা লেবেল মুছে ফেলা বা পরিবর্তন করা;',
        'terms_prohibited_activities_4' => 'ওয়েবসাইট ছাড়া অন্য কোনো ইন্টারফেস ব্যবহার করে পরিষেবাগুলি ব্যবহার করা;',
        'terms_prohibited_activities_5' => 'অন্যান্য ব্যবহারকারীদের ওয়েবসাইট এবং/বা পরিষেবার ব্যবহারে হস্তক্ষেপ করা;',
        'terms_prohibited_activities_6' => 'বট বা অন্যান্য স্বয়ংক্রিয় পদ্ধতি ব্যবহার করে ওয়েবসাইট এবং/বা পরিষেবাগুলি অ্যাক্সেস বা ব্যবহার করা;',
        'terms_prohibited_activities_7' => 'আমাদের সুস্পষ্ট অনুমতি ছাড়া, যে কোনো উপাদান আপলোড বা প্রেরণ (বা আপলোড বা প্রেরণের চেষ্টা) করা যা প্যাসিভ বা অ্যাকটিভ তথ্য সংগ্রহ বা প্রেরণ প্রক্রিয়া হিসেবে কাজ করে, যার মধ্যে ওয়েব বাগ, কুকি বা অন্যান্য অনুরূপ স্পাইওয়্যার ডিভাইস সীমাবদ্ধ নয়;',
        'terms_prohibited_activities_8' => 'পরিষেবার চেহারা বা ফাংশনের অনুকরণ করে এমন <b>“ফ্রেমিং,” “মিররিং,”</b> বা অন্যথায় সিমুলেট করা;',
        'terms_prohibited_activities_9' => 'যে কোনো প্রযোজ্য আইন বা নিয়ম লঙ্ঘন করা, কপিরাইট লঙ্ঘন, ট্রেডমার্ক লঙ্ঘন, মানহানি, গোপনীয়তা আক্রমণ, পরিচয় চুরি, হ্যাকিং, ক্র্যাকিং বা জাল সফটওয়্যার বিতরণ সহ কিন্তু সীমাবদ্ধ নয় এমন কোনো অবৈধ কার্যকলাপকে উৎসাহিত বা প্রচার করা;',
        'terms_prohibited_activities_10' => 'ওয়েবসাইটের সোর্স কোডে কোনো পরিবর্তন করা এবং/বা যে কোনো উপায়ে হস্তক্ষেপ করা এবং ওয়েবসাইট বা অন্য কোনো তৃতীয় পক্ষের ক্ষতি করতে পারে এমন কোনো সফটওয়্যার এবং/বা অ্যাপ্লিকেশন আপলোড করা;',
        'terms_prohibited_activities_11' => 'ওয়েবসাইটে অন্তর্ভুক্ত বা পরিষেবা প্রদানের জন্য ব্যবহৃত যে কোনো সফটওয়্যার বা অন্যান্য প্রযুক্তিকে বিচ্ছিন্ন করা, ডিকম্পাইল করা বা অন্যথায় রিভার্স ইঞ্জিনিয়ার করা।',
        'terms_prohibited_activities_12' => 'আপনি স্বীকার করেন যে আমাদের অন্য যে কোনো অধিকারের ক্ষতি না করে, যদি আমরা নির্ধারণ করি যে আপনার ওয়েবসাইটের ব্যবহার এই শর্তাবলী বা প্রযোজ্য কোনো আইনের বিধানের সাথে সামঞ্জস্যপূর্ণ নয়, তবে আমরা আপনার ওয়েবসাইট এবং/বা পরিষেবাগুলিতে অ্যাক্সেস ব্লক করতে পারি।',
        'terms_intellectual_property_title' => '৬. বুদ্ধিবৃত্তিক সম্পত্তি অধিকার',
        'terms_intellectual_property_1' => 'ওয়েবসাইট এবং এর বিষয়বস্তু, যার মধ্যে ভিডিও উপকরণ, পাঠ্য, ছবি, লোগো, ডিজাইন, সঙ্গীত, শব্দ, চিত্র, ট্রেডমার্ক এবং ওয়েবসাইটে অন্তর্ভুক্ত অন্যান্য বিষয়বস্তু আমাদের বা তৃতীয় পক্ষের বুদ্ধিবৃত্তিক সম্পত্তি অধিকার দ্বারা সুরক্ষিত।',
        'terms_intellectual_property_2' => 'আমাদের এবং ব্যবহারকারীর মধ্যে, আমরা ওয়েবসাইট এবং পরিষেবাগুলির সমস্ত অধিকার, শিরোনাম এবং স্বার্থ ধরে রাখি। ওয়েবসাইট এবং/বা পরিষেবাগুলির ব্যবহার ব্যবহারকারীকে ওয়েবসাইট এবং/বা পরিষেবাগুলিতে অন্তর্ভুক্ত কোনো বুদ্ধিবৃত্তিক সম্পত্তি অধিকার প্রদান করে না, শুধুমাত্র এই শর্তাবলীর সাথে সামঞ্জস্য রেখে ওয়েবসাইট এবং/বা পরিষেবাগুলি ব্যবহারের অধিকার ছাড়া।',
        'terms_intellectual_property_3' => 'ব্যবহারকারী কেবল ব্যক্তিগত এবং অ-বাণিজ্যিক ব্যবহারের জন্য ওয়েবসাইট এবং/বা পরিষেবাগুলি ব্যবহার করতে পারেন।',
        'terms_intellectual_property_4' => 'আপনি বা আপনি অন্য কোনো পক্ষকে পরিবর্তন, ডিকম্পাইল, বিচ্ছিন্ন, রিভার্স ইঞ্জিনিয়ার, কপি, স্থানান্তর, ডেরিভেটিভ কাজ তৈরি, ভাড়া, সাব-লাইসেন্স, বিতরণ, ফ্রেমযুক্ত পুনরুৎপাদন, পুনঃপ্রকাশ, স্ক্র্যাপ, ডাউনলোড, প্রদর্শন, প্রেরণ, পোস্ট, ইজারা বা বিক্রয় করতে দেবেন না, সম্পূর্ণ বা আংশিকভাবে, এই শর্তাবলী অনুসারে ওয়েবসাইট বা পরিষেবাগুলি ব্যবহার ছাড়া অন্য কোনো উদ্দেশ্যে বা আমাদের সুস্পষ্ট, পূর্ব লিখিত অনুমতি ছাড়া ওয়েবসাইটের বিষয়বস্তু শোষণ করতে পারবেন না।',
        'terms_liability_title' => '৭. দায়বদ্ধতার সীমাবদ্ধতা',
        'terms_liability_1' => 'আমরা এমন ক্ষতি বা ক্ষতির জন্য দায়বদ্ধ হতে পারি না যা এই শর্তাবলীর অ-পালন বা অনুপযুক্ত পালনের ফলে ঘটে যা (i) আপনার কারণে, (ii) চুক্তির তৃতীয় পক্ষের অপ্রত্যাশিত এবং অপ্রতিরোধ্য কাজের জন্য, বা (iii) ফোর্স ম্যাজিওর ইভেন্টের জন্য দায়ী।',
        'terms_liability_2' => 'এই শর্তাবলীতে এমন কিছু নেই যা আপনার প্রতি আমাদের দায়বদ্ধতা বাদ বা সীমিত করার উদ্দেশ্যে, যেখানে তা করা বেআইনি হবে, বিশেষ করে নিম্নলিখিত ক্ষেত্রে:',
        'terms_liability_3' => '(i) আমাদের অবহেলার ফলে মৃত্যু বা ব্যক্তিগত আঘাত,',
        'terms_liability_4' => '(ii) প্রতারণা বা প্রতারণামূলক ভুল উপস্থাপনা, এবং',
        'terms_liability_5' => '(iii) বাংলাদেশের আইনের অধীনে বাদ বা সীমিত করা যায় না এমন অন্য যে কোনো দায়বদ্ধতা।',
        'terms_liability_6' => 'উপরোক্ত সাধারণতার ব্যতিক্রম না করে, আমরা কোনো তৃতীয় পক্ষের দ্বারা ওয়েবসাইট বা পরিষেবার মাধ্যমে প্রেরিত বাগ, ভাইরাস, ট্রোজান হর্স বা অনুরূপ কিছুর জন্য কোনো দায়বদ্ধতা বা দায়িত্ব গ্রহণ করি না, যদি না আমরা দোষী হই।',
        'terms_liability_7' => 'আমরা আমাদের সর্বোত্তম প্রচেষ্টা ব্যবহার করি যাতে ওয়েবসাইট কোনো ত্রুটি, ভুল বা বিষয়বস্তুর অশুদ্ধতা থেকে মুক্ত থাকে। যদি এমন ত্রুটি, ভুল বা অশুদ্ধতা ঘটে, আমরা তা অবিলম্বে সংশোধন করব।',
        'terms_liability_8' => 'আপনি আমাদেরকে কোনো তৃতীয় পক্ষের ক্ষতির জন্য ক্ষতিপূরণ দিতে সম্মত হন, যা ওয়েবসাইট এবং/বা পরিষেবার সম্পর্কে আপনার এই শর্তাবলী লঙ্ঘনের ফলে ঘটে।',
        'terms_liability_9' => 'আমরা কোনো টেলিফোন বা নেটওয়ার্ক লাইন, কম্পিউটার অনলাইন সিস্টেম, সার্ভার বা প্রদানকারী, হার্ডওয়্যার, সফটওয়্যার, প্রযুক্তিগত সমস্যা বা ইন্টারনেটে ট্রাফিক জটিলতা (বা ইন্টারনেটের অপ্রাপ্যতা) বা ওয়েবসাইট বা পরিষেবাগুলির সাথে আপনার ব্রাউজার এবং/বা অন্যান্য সরঞ্জামের অসামঞ্জস্যতার জন্য কোনো সমস্যা বা প্রযুক্তিগত ত্রুটির জন্য দায়ী নই। উপরোক্ত সাধারণতার ব্যতিক্রম না করে, আমরা আপনার ইন্টারনেট ব্যবহারের জন্য কোনো দায়িত্ব বা ঝুঁকি গ্রহণ করি না।',
        'terms_third_party_title' => '৮. তৃতীয় পক্ষের পরিষেবা বা বিষয়বস্তু',
        'terms_third_party_1' => 'পরিষেবাগুলি ব্যবহার করার সময়, আপনি তৃতীয় পক্ষের দ্বারা প্রদত্ত বিষয়বস্তু বা পরিষেবা দেখতে পারেন, যার মধ্যে তৃতীয় পক্ষের প্ল্যাটফর্ম সম্পর্কিত বিজ্ঞাপন এবং পর্যালোচনা রয়েছে।',
        'terms_third_party_2' => 'আমরা এই ধরনের বিষয়বস্তু বা পরিষেবাগুলি নিয়ন্ত্রণ, সমর্থন বা গ্রহণ করি না এবং এটি সবসময় সঠিক বা বর্তমান নাও হতে পারে।',
        'terms_third_party_3' => 'তদনুসারে, আমরা সুপারিশ করি যে আপনি এই তথ্যের উপর নির্ভর করার আগে স্বাধীনভাবে সমস্ত তথ্য যাচাই করুন, এবং এই তথ্যের উপর ভিত্তি করে নেওয়া যে কোনো সিদ্ধান্ত বা পদক্ষেপ আপনার একমাত্র দায়িত্ব।',
        'terms_links_title' => '৯. লিঙ্ক',
        'terms_links_1' => 'ওয়েবসাইটে তৃতীয় পক্ষের দ্বারা নিয়ন্ত্রিত বা প্রদত্ত অন্যান্য ওয়েবসাইট বা সফটওয়্যারের লিঙ্ক, বিষয়বস্তু, বিজ্ঞাপন, প্রচার, লোগো এবং অন্যান্য উপকরণ থাকতে পারে (<b>“লিঙ্ক”</b>)। আমরা আপনাকে সতর্ক করি যে এই ওয়েবসাইট, সফটওয়্যার বা উপকরণ ব্যবহারের সাথে জড়িত ঝুঁকিগুলি বুঝতে হবে, এই ওয়েবসাইট বা সফটওয়্যারের মাধ্যমে বা এই উপকরণের উপর ভিত্তি করে কিছু পুনরুদ্ধার, ব্যবহার, নির্ভর বা ক্রয় করার আগে। এই ধরনের লিঙ্কগুলি শুধুমাত্র আপনার সুবিধার জন্য প্রদান করা হয়, এবং আপনি সম্মত হন যে কোনো পরিস্থিতিতে আপনি আমাদেরকে অন্যান্য ওয়েবসাইটে উপলব্ধ কোনো বিষয়বস্তু, পণ্য বা পরিষেবার ব্যবহার বা নির্ভরতার কারণে সৃষ্ট কোনো ক্ষতি বা ক্ষতির জন্য দায়ী করবেন না।',
        'terms_links_2' => 'ওয়েবসাইটে লিঙ্কগুলির অন্তর্ভুক্তি আমাদের এবং এই ওয়েবসাইট, সফটওয়্যার বা তাদের অপারেটরদের মধ্যে সমর্থন, অনুমোদন, স্পনসরশিপ, অধিভুক্তি বা অন্য কোনো সংযোগ নয়।',
        'terms_links_3' => 'আমরা এই ধরনের কোনো বা সমস্ত লিঙ্ক পর্যালোচনা করিনি এবং এর দ্বারা উল্লিখিত ওয়েবসাইট বা সফটওয়্যারের কোনো বিষয়বস্তুর জন্য দায়ী নই। আমরা আপনাকে সতর্ক করি যে এই ওয়েবসাইট বা সফটওয়্যার ব্যবহারের সাথে জড়িত ঝুঁকিগুলি বুঝতে হবে, এই ওয়েবসাইট বা সফটওয়্যারের মাধ্যমে বা এই উপকরণের উপর ভিত্তি করে কিছু পুনরুদ্ধার, ব্যবহার, নির্ভর বা ক্রয় করার আগে। কোনো পরিস্থিতিতে আপনি আমাদেরকে অন্যান্য ওয়েবসাইটে উপলব্ধ কোনো বিষয়বস্তু, পণ্য বা পরিষেবার ব্যবহার বা নির্ভরতার কারণে সৃষ্ট কোনো ক্ষতি বা ক্ষতির জন্য দায়ী করবেন না।',
        'terms_links_4' => 'এই ধরনের তৃতীয় পক্ষের ওয়েবসাইটের শর্তাবলী এবং নীতিগুলি পর্যালোচনা করা আপনার দায়িত্ব, এবং আমরা দৃঢ়ভাবে সুপারিশ করি যে আপনি এই তৃতীয় পক্ষের সাথে জড়িত হওয়ার আগে সেগুলি সাবধানে পর্যালোচনা করুন।',
        'terms_miscellaneous_title' => '১০. বিবিধ',
        'terms_miscellaneous_1' => 'আমরা সময়ে সময়ে যে কোনো পরিষেবা সংশোধন, পরিবর্তন বা বন্ধ করতে পারি এবং/বা ভবিষ্যতের জন্য নতুন পরিষেবা প্রবর্তন করতে পারি।',
        'terms_miscellaneous_2' => 'আমরা সময়ে সময়ে এই শর্তাবলী পরিবর্তন করতে পারি। যখন আমরা তা করি, আমরা এই পৃষ্ঠার শীর্ষে সর্বাধুনিক সংস্করণ প্রকাশ করে এবং তারিখ সংশোধন করে আপনাকে বিজ্ঞপ্তি দেব এবং যে কোনো পরিবর্তন প্রকাশের পরপরই কার্যকর হবে। পরিবর্তনগুলি কার্যকর হওয়ার পরে ওয়েবসাইট ব্যবহার চালিয়ে যাওয়ার মাধ্যমে, আপনি সংশোধিত শর্তাবলীতে সম্মত হিসেবে বিবেচিত হবেন।',
        'terms_miscellaneous_3' => 'ব্যবহারকারী সম্মত হন যে ওয়েবসাইটে বা থেকে তথ্য প্রেরণ এই শর্তাবলীতে উল্লিখিত সম্পর্ক থেকে বিচ্যুত কোনো সম্পর্ক তৈরি করে না।',
        'terms_miscellaneous_4' => 'এই শর্তাবলী এবং গোপনীয়তা নীতি, সময়ে সময়ে সংশোধিত, আমাদের এবং ব্যবহারকারীর মধ্যে একমাত্র বৈধ চুক্তি গঠন করে, এবং শর্তাবলী বা গোপনীয়তা নীতিতে অন্তর্ভুক্ত নয় এমন কোনো উপস্থাপনা, প্রতিশ্রুতি, সম্মতি বা অঙ্গীকার, লিখিত বা মৌখিক, পক্ষগুলির উপর বাধ্যতামূলক হবে না।',
        'terms_miscellaneous_5' => 'আমাদের পক্ষ থেকে কোনো অধিকার, ক্ষমতা বা প্রতিকার প্রয়োগে ব্যর্থতা বা বিলম্ব তার মওকুফ হিসেবে কাজ করবে না, এবং এই ধরনের কোনো অধিকার, ক্ষমতা বা প্রতিকারের একক বা আংশিক প্রয়োগ অন্য কোনো বা আরও প্রয়োগ বা অন্য যে কোনো অধিকার, ক্ষমতা বা প্রতিকারের প্রয়োগকে বাধা দেবে না।',
        'terms_miscellaneous_6' => 'যদি এই শর্তাবলীর কোনো বিধান প্রযোজ্য আইনের অধীনে কোনো যোগ্য আদালত দ্বারা অপ্রয়োগযোগ্য বলে ধরা হয়, তবে এই ধরনের বিধান এই শর্তাবলী থেকে বাদ দেওয়া হবে এবং বাকি শর্তাবলী এমনভাবে ব্যাখ্যা করা হবে যেন এই বিধানটি বাদ দেওয়া হয়েছে এবং এর শর্তাবলী অনুসারে প্রয়োগযোগ্য হবে; তবে, এই ধরনের ঘটনায় এই শর্তাবলী এমনভাবে ব্যাখ্যা করা হবে যাতে প্রযোজ্য আইনের সাথে সামঞ্জস্যপূর্ণ এবং অনুমোদিত সর্বাধিক পরিমাণে, এই ধরনের আদালত দ্বারা নির্ধারিত বাদ দেওয়া বিধানের অর্থ এবং উদ্দেশ্য কার্যকর করা যায়।',
        'terms_miscellaneous_7' => 'আমরা এখানে আমাদের সমস্ত অধিকার এবং বাধ্যবাধকতা যে কোনো তৃতীয় পক্ষের কাছে হস্তান্তর বা অর্পণ করতে পারি, তবে এটি আপনার অধিকারের উপর নেতিবাচক প্রভাব ফেলবে না। তদুপরি, উপরোক্ত থেকে ব্যতিক্রম না করে, ওয়েবসাইট এবং/বা যে কোনো পরিষেবা তৃতীয় পক্ষ দ্বারা পরিচালিত হতে পারে। আপনি এই শর্তাবলীর অধীনে আপনার কোনো অধিকার বা বাধ্যবাধকতা হস্তান্তর, অর্পণ বা কোনো উপায়ে বন্ধক দিতে পারবেন না।',
        'terms_miscellaneous_8' => 'এই শর্তাবলী বাংলাদেশের আইন দ্বারা নিয়ন্ত্রিত হবে।',
        'terms_miscellaneous_9' => 'এই শর্তাবলী থেকে বা এর সাথে সম্পর্কিত সমস্ত বিরোধের জন্য একচেটিয়া বিচারিক স্থান হবে বাংলাদেশের আদালত।',

        'privacy_purpose_title' => 'বিজ্ঞপ্তির উদ্দেশ্য',
        'privacy_purpose_text' => 'এই ডেটা গোপনীয়তা বিজ্ঞপ্তির ("বিজ্ঞপ্তি") উদ্দেশ্য হল ব্যাখ্যা করা যে Floventra ("Floventra" বা "আমরা" বা "আমাদের") কীভাবে, ডেটা নিয়ন্ত্রক হিসেবে, আপনার ব্যক্তিগত ডেটা প্রক্রিয়া করবে যা আপনি আমাদেরকে প্রদান করেন যখন আপনি ওয়েবসাইট floventus.com ("ওয়েবসাইট") পরিদর্শন করেন, বা আমরা তৃতীয় পক্ষের কাছ থেকে পাই, যাতে আপনাকে আপনার আগ্রহী পেশাদারদের সাথে সংযোগ করা যায়।',
        'privacy_data_categories_title' => 'কোন কোন বিভাগের ব্যক্তিগত ডেটা প্রক্রিয়া করা হবে?',
        'privacy_data_categories_text' => 'আমরা আপনার সম্পর্কে নিম্নলিখিত বিভাগের ব্যক্তিগত ডেটা সংগ্রহ এবং প্রক্রিয়া করি:',
        'privacy_data_collection_title' => 'আপনার ডেটা কীভাবে সংগ্রহ করা হয়?',
        'privacy_data_collection_text' => 'আমরা আপনার ব্যক্তিগত ডেটা সংগ্রহ করব:',
        'privacy_data_collection_direct' => 'সরাসরি আপনার কাছ থেকে, যখন আপনি আমাদের ওয়েবসাইটে আপনার পরিচয় ডেটা প্রদান করেন; এবং/বা',
        'privacy_data_collection_indirect' => 'পরোক্ষভাবে:',
        'privacy_data_collection_indirect_1' => 'যখন আমরা তৃতীয় পক্ষের কাছ থেকে আপনার সম্পর্কে পরিচয় ডেটা পাই (যার মধ্যে বিনিয়োগ শিক্ষা প্রতিষ্ঠান, অংশীদার / অ্যাফিলিয়েট / মার্কেটার / ডিজিটাল এজেন্সি অন্তর্ভুক্ত); এবং/বা',
        'privacy_data_collection_indirect_2' => 'যখন আমরা কুকি বা অনুরূপ প্রযুক্তি (কুকি নীতিতে সংজ্ঞায়িত) ব্যবহার করে আমাদের ওয়েবসাইটে আপনার ব্রাউজিং সম্পর্কিত ডেটা সংগ্রহ করি।',
        'privacy_data_collection_note' => 'আপনি আমাদেরকে আপনার ব্যক্তিগত ডেটা প্রদান করতে বাধ্য নন। তবে, আপনার ব্যক্তিগত ডেটা প্রদান না করলে আমরা আপনাকে আপনার আগ্রহী পেশাদারদের সাথে সংযোগ করতে পারব না।',
        'privacy_data_sharing_title' => 'আমার ব্যক্তিগত ডেটা কার সাথে শেয়ার করা হবে?',
        'privacy_data_sharing_text' => 'আমরা আপনার ব্যক্তিগত ডেটা শেয়ার করব:',
        'privacy_data_sharing_1' => 'আমাদের গ্রুপের মধ্যে;',
        'privacy_data_sharing_2' => 'আমাদের অংশীদারদের সাথে, তাদের নিজস্ব প্রক্রিয়াকরণের উদ্দেশ্যে, যার মধ্যে আপনার আগ্রহী হতে পারে এমন তাদের পরিষেবা এবং/বা পণ্য সম্পর্কে তথ্য প্রদান করা অন্তর্ভুক্ত, তবে আপনি এই ধরনের শেয়ারিংয়ের জন্য পূর্বে সম্মতি দিয়েছেন। এই অংশীদারদের মধ্যে বিডিএসই নিয়ন্ত্রিত বিনিয়োগ শিক্ষা প্রতিষ্ঠান, ডেটা ব্রোকার এবং মধ্যস্থতাকারী অন্তর্ভুক্ত;',
        'privacy_data_sharing_3' => 'তৃতীয় পক্ষের সাথে যারা আমাদের স্টোরেজ এবং হোস্টিং প্রদানকারী, বিশ্লেষণাত্মক, প্রযুক্তিগত এবং ডায়াগনস্টিক পরিষেবার মতো পরিষেবা প্রদান করে;',
        'privacy_data_sharing_4' => 'আমাদের পরামর্শদাতাদের সাথে, বিশেষ করে আমাদের সংবিধিবদ্ধ বাধ্যবাধকতা পালনের জন্য, বিশেষত হিসাবরক্ষণ, নিরীক্ষণ এবং অভ্যন্তরীণ নিয়ন্ত্রণের ক্ষেত্রে;',
        'privacy_data_sharing_5' => 'আমাদের কোম্পানির সমস্ত বা অংশ এবং এর সম্পদের তৃতীয় পক্ষের কাছে বিক্রয় বা ব্যবসায় পুনর্গঠন বা পুনর্গঠন (বিলুপ্তি বা লিকুইডেশন সহ) এর অংশ হিসেবে;',
        'privacy_data_sharing_6' => 'প্রযোজ্য আইন দ্বারা প্রয়োজনীয় বা অনুমোদিত হলে, সরকারি কর্তৃপক্ষ, আদালত, বাহ্যিক উপদেষ্টা এবং অনুরূপ তৃতীয় পক্ষের সাথে।',
        'privacy_cross_border_title' => 'ক্রস-বর্ডার ডেটা স্থানান্তর',
        'privacy_cross_border_text_1' => 'আমরা আপনার ব্যক্তিগত ডেটা বাংলাদেশের বাইরে স্থানান্তর করি। কিছু প্রাপক এমন দেশে অবস্থিত যেগুলির জন্য বাংলাদেশ সরকার পর্যাপ্ততা নিয়ম জারি করেছে, যেমন ইসরায়েল। এই স্থানান্তরটি বাংলাদেশের ডেটা সুরক্ষা আইনের দৃষ্টিকোণ থেকে পর্যাপ্ত ডেটা সুরক্ষা প্রদান হিসেবে স্বীকৃত।',
        'privacy_cross_border_text_2' => 'আপনার ব্যক্তিগত ডেটার কিছু প্রাপক এমন দেশে অবস্থিত হতে পারে যেগুলির জন্য বাংলাদেশ সরকার পর্যাপ্ততা নিয়ম জারি করেনি।',
        'privacy_cross_border_text_3' => 'বাংলাদেশের ডেটা সুরক্ষা আইনের স্ট্যান্ডার্ড চুক্তিভিত্তিক ধারা বা অন্যান্য পর্যাপ্ত উপায়ের উপর ভিত্তি করে উপযুক্ত ডেটা স্থানান্তর চুক্তিতে প্রবেশ করে, আমরা প্রতিষ্ঠিত করেছি যে বাংলাদেশের বাইরে অবস্থিত সমস্ত অন্যান্য প্রাপক ব্যক্তিগত ডেটার জন্য পর্যাপ্ত স্তরের ডেটা সুরক্ষা প্রদান করবে এবং দুর্ঘটনাজনিত বা বেআইনি ধ্বংস, দুর্ঘটনাজনিত ক্ষতি বা পরিবর্তন, অননুমোদিত প্রকাশ বা অ্যাক্সেস এবং অন্যান্য সমস্ত বেআইনি প্রক্রিয়াকরণের বিরুদ্ধে উপযুক্ত প্রযুক্তিগত এবং সাংগঠনিক সুরক্ষা ব্যবস্থা রয়েছে। যে কোনো পরবর্তী স্থানান্তর (বাংলাদেশের বাইরে আমাদের অ্যাফিলিয়েট সহ) প্রযোজ্য আইন দ্বারা প্রয়োজনীয় উপযুক্ত পরবর্তী স্থানান্তর প্রয়োজনীয়তার অধীন।',
        'privacy_retention_title' => 'ধরে রাখা',
        'privacy_retention_text' => 'আমরা সংগৃহীত ব্যক্তিগত ডেটা শুধুমাত্র এই বিজ্ঞপ্তিতে উল্লিখিত প্রক্রিয়াকরণের উদ্দেশ্য অর্জনের জন্য কঠোরভাবে প্রয়োজনীয় সময় পর্যন্ত সংরক্ষণ করব এবং বাংলাদেশের ডেটা সুরক্ষা আইনের সাথে সামঞ্জস্য রেখে। যখন আমাদের আর আপনার ব্যক্তিগত ডেটা ব্যবহারের প্রয়োজন হবে না, তখন এটি মুছে ফেলা হবে এবং/বা বেনামী করা হবে যাতে এটি থেকে ব্যক্তিদের আর চিহ্নিত করা না যায় (আইনি বা নিয়ন্ত্রক বাধ্যবাধকতা পালন বা আইনি দাবি গ্রহণ বা প্রতিরক্ষার জন্য ধরে রাখা প্রয়োজন হওয়া পর্যন্ত)।',
        'privacy_rights_title' => 'আপনার অধিকার',
        'privacy_rights_text' => 'বাংলাদেশের ডেটা সুরক্ষা আইনের অধীনে, আপনার নিম্নলিখিত অধিকার রয়েছে:',
        'privacy_right_access' => '<b>অ্যাক্সেসের অধিকার:</b> আপনার সম্পর্কিত ব্যক্তিগত ডেটা প্রক্রিয়া করা হচ্ছে কিনা তা আমাদের কাছ থেকে নিশ্চিতকরণ পাওয়ার অধিকার আপনার রয়েছে, এবং যদি তা হয়, তবে ব্যক্তিগত ডেটার অ্যাক্সেস অনুরোধ করার অধিকার। অ্যাক্সেস তথ্যের মধ্যে রয়েছে – অন্যান্যের মধ্যে – প্রক্রিয়াকরণের উদ্দেশ্য, সংশ্লিষ্ট ব্যক্তিগত ডেটার বিভাগ এবং যাদের কাছে ব্যক্তিগত ডেটা প্রকাশ করা হয়েছে বা হবে তাদের প্রাপক বা প্রাপকদের বিভাগ। আপনার প্রক্রিয়াকৃত ব্যক্তিগত ডেটার একটি অনুলিপি পাওয়ার অধিকার রয়েছে। আপনার দ্বারা অনুরোধিত অতিরিক্ত অনুলিপির জন্য, আমরা প্রশাসনিক খরচের উপর ভিত্তি করে যুক্তিসঙ্গত ফি চার্জ করতে পারি।',
        'privacy_right_rectification' => '<b>সংশোধনের অধিকার:</b> আপনার সম্পর্কিত অসঠিক ব্যক্তিগত ডেটা সংশোধনের জন্য আমাদের কাছ থেকে পাওয়ার অধিকার আপনার রয়েছে। প্রক্রিয়াকরণের উদ্দেশ্যের উপর নির্ভর করে, আপনার অসম্পূর্ণ ব্যক্তিগত ডেটা সম্পূর্ণ করার অধিকার রয়েছে, যার মধ্যে একটি সম্পূরক বিবৃতি প্রদানের মাধ্যমে।',
        'privacy_right_erasure' => '<b>মুছে ফেলার অধিকার (ভুলে যাওয়ার অধিকার):</b> আপনার ব্যক্তিগত ডেটা মুছে ফেলার জন্য আমাদের কাছে অনুরোধ করার অধিকার আপনার রয়েছে।',
        'privacy_right_restriction' => '<b>প্রক্রিয়াকরণের সীমাবদ্ধতার অধিকার:</b> আপনার ব্যক্তিগত ডেটার প্রক্রিয়াকরণ সীমিত করার অনুরোধ করার অধিকার আপনার রয়েছে। এই ক্ষেত্রে, সংশ্লিষ্ট ডেটা চিহ্নিত করা হবে এবং আমরা কেবল নির্দিষ্ট উদ্দেশ্যে এটি প্রক্রিয়া করতে পারি।',
        'privacy_right_portability' => '<b>ডেটা পোর্টেবিলিটির অধিকার:</b> আপনার সম্পর্কিত ব্যক্তিগত ডেটা, যা আপনি আমাদেরকে প্রদান করেছেন, তা একটি কাঠামোগত, সাধারণভাবে ব্যবহৃত এবং মেশিন-পাঠযোগ্য ফরম্যাটে পাওয়ার অধিকার আপনার রয়েছে এবং আপনার এই ব্যক্তিগত ডেটা আমাদের বাধা ছাড়াই অন্য একটি সত্তায় প্রেরণ করার অধিকার রয়েছে।',
        'privacy_right_object' => '<b>আপত্তি করার অধিকার:</b> আপনার নির্দিষ্ট পরিস্থিতির সাথে সম্পর্কিত কারণে যে কোনো সময় আমাদের দ্বারা আপনার ব্যক্তিগত ডেটার প্রক্রিয়াকরণে আপত্তি করার অধিকার আপনার রয়েছে এবং আমরা আপনার ব্যক্তিগত ডেটা আর প্রক্রিয়া না করতে বাধ্য হতে পারি। যদি আপনার আপত্তি করার অধিকার থাকে এবং আপনি এই অধিকার প্রয়োগ করেন, তবে আপনার ব্যক্তিগত ডেটা আমাদের দ্বারা এই ধরনের উদ্দেশ্যে আর প্রক্রিয়া করা হবে না। এই অধিকার প্রয়োগে কোনো খরচ হবে না। এই ধরনের আপত্তির অধিকার বিশেষ করে অস্তিত্ব নাও থাকতে পারে, যদি আপনার ব্যক্তিগত ডেটার প্রক্রিয়াকরণ কোনো চুক্তিতে প্রবেশের পূর্বে পদক্ষেপ নেওয়া বা ইতিমধ্যে সম্পন্ন চুক্তি পালনের জন্য প্রয়োজনীয় হয়।',
        'privacy_right_withdraw' => '<b>আপনার সম্মতি প্রত্যাহার করার অধিকার:</b> যেখানে আপনার ব্যক্তিগত ডেটার প্রক্রিয়াকরণ আপনার সম্মতির উপর ভিত্তি করে, আপনার যে কোনো সময় আপনার সম্মতি প্রত্যাহার করার অধিকার রয়েছে। এই ধরনের সম্মতি প্রত্যাহারের অধিকার প্রত্যাহারের আগে আপনি আমাদেরকে দেওয়া সম্মতির উপর ভিত্তি করে প্রক্রিয়াকরণের বৈধতাকে প্রভাবিত করে না।',
        'privacy_right_after_death' => '<b>আপনার মৃত্যুর পরে আপনার ডেটার অধিকার:</b> আপনার মৃত্যুর পরে আপনার সম্পর্কিত ব্যক্তিগত ডেটার ধরে রাখা, মুছে ফেলা এবং যোগাযোগ সম্পর্কিত নির্দেশনা দেওয়ার অধিকার আপনার রয়েছে।',
        'privacy_rights_note' => 'দয়া করে মনে রাখবেন যে প্রযোজ্য বাংলাদেশের ডেটা গোপনীয়তা আইনের অধীনে এই অধিকারগুলি সীমিত হতে পারে।',
        'privacy_rights_contact' => 'আপনি যদি এই অধিকারগুলির মধ্যে কোনোটি প্রয়োগ করতে চান, তবে নীচে যোগাযোগ করুন বিভাগে উল্লিখিত হিসেবে আমাদের সাথে যোগাযোগ করুন।',
        'privacy_rights_complaint' => 'আপনার বাংলাদেশের যোগ্য ডেটা গোপনীয়তা তত্ত্বাবধায়ক কর্তৃপক্ষ, যা বাংলাদেশের তথ্য ও যোগাযোগ প্রযুক্তি মন্ত্রণালয়, এর কাছে অভিযোগ দায়ের করার অধিকারও রয়েছে।',
        'privacy_contact_title' => 'আমাদের সাথে যোগাযোগ করুন',
        'privacy_contact_text' => 'যে ব্যক্তিরা এই বিজ্ঞপ্তি সম্পর্কে কোনো প্রশ্ন আছে তাদের <a href="mailto:info@floventus.com">info@floventus.com</a> এ যোগাযোগ করা উচিত।',
        'privacy_changes_title' => 'গোপনীয়তা বিজ্ঞপ্তির পরিবর্তন',
        'privacy_changes_text' => 'এই গোপনীয়তা বিজ্ঞপ্তি পরিবর্তন সাপেক্ষে। আপনাকে এই ধরনের যে কোনো পরিবর্তন সম্পর্কে যথাযথভাবে বিজ্ঞপ্তি দেওয়া হবে।',
