        'terms_eligibility_3' => 'أن تكون لديك الحق والسلطة والقدرة على قبول هذه الشروط والالتزام بجميع بنودها وشروطها؛',
        'terms_eligibility_4' => 'ألا تكون محظورًا من استخدام الموقع و/أو الخدمات بموجب قوانين السعودية أو البلد الذي تقيم فيه أو تتواجد فيه أثناء استخدام الموقع.',
        'terms_restricted_territories_title' => '4. الأراضي المقيدة',
        'terms_restricted_territories_1' => 'دون الإخلال بعمومية ما سبق، يجوز لنا تقييد توافر الموقع و/أو الخدمات (أو أي جزء منها) للمستخدمين الموجودين في أراضٍ يكون فيها الإطار القانوني والتنظيمي غير متوافق مع تقديم الخدمات.',
        'terms_restricted_territories_2' => 'يجوز لنا فرض متطلبات أو شروط إضافية قبل قبول المستخدمين المقيمين في أو من دول معينة حيث يكون ذلك ضروريًا للامتثال لقوانين السعودية أو الإقليم الذي يقيم فيه المستخدمون. علاوة على ذلك، يُقر بأنه إذا سافر أي مستخدم إلى الأراضي المقيدة، فقد يكون الموقع و/أو الخدمات غير متاحة و/أو محظورة هناك.',
        'terms_prohibited_activities_title' => '5. الأنشطة المحظورة',
        'terms_prohibited_activities_1' => 'تتعهد باستخدام الموقع والخدمات بطريقة محترمة، وتتعهد بعدم:',
        'terms_prohibited_activities_2' => 'الارتباط بالموقع و/أو استخدام الموقع بغرض تحميل أو تنزيل أو توزيع أو نشر أو نقل (أ) معلومات أو مواد أخرى بطريقة تنتهك أي حقوق، بما في ذلك حقوق الملكية الفكرية، حماية حقوق الخصوصية أو أي حق آخر؛ (ب) معلومات أو مواد أخرى محظورة النشر أو الاستخدام لأنها تشكل تهديدًا أو ضررًا أو إهانة أو تشهيرًا أو عنصرية أو محتوى غير لائق؛ (ج) معلومات أو مواد أخرى تحتوي على فيروس أو برمجيات أخرى قد تتلف أنظمتنا الحاسوبية أو أي طرف ثالث أو بطريقة قد تحد أو تمنع الآخرين من استخدام الموقع؛ (د) معلومات أو مواد أخرى تنتهك أي قانون؛ أو (هـ) معلومات أو مواد أخرى تحتوي على إعلان من أي نوع بدون إذننا الكتابي المسبق؛',
        'terms_prohibited_activities_3' => 'حذف أو تعديل أي إسنادات أو إشعارات قانونية أو تسميات أو علامات ملكية أخرى على الموقع؛',
        'terms_prohibited_activities_4' => 'استخدام الخدمات باستخدام أي واجهة غير الموقع؛',
        'terms_prohibited_activities_5' => 'التدخل في استخدام الآخرين للموقع و/أو الخدمات؛',
        'terms_prohibited_activities_6' => 'استخدام بوتات أو طرق آلية أخرى للوصول إلى أو استخدام الموقع و/أو الخدمات؛',
        'terms_prohibited_activities_7' => 'تحميل أو نقل (أو محاولة تحميل أو نقل)، بدون إذننا الصريح، أي مادة تعمل كآلية جمع أو نقل معلومات سلبية أو نشطة، بما في ذلك، على سبيل المثال لا الحصر، أخطاء الويب، الكوكيز أو أجهزة التجسس المشابهة؛',
        'terms_prohibited_activities_8' => 'الانخراط في "إطار"، "مرآة"، أو غير ذلك محاكاة مظهر أو وظيفة الخدمات؛',
        'terms_prohibited_activities_9' => 'انتهاك أي قوانين أو لوائح سارية، تشجيع أو ترويج أي نشاط غير قانوني بما في ذلك، ولكن ليس محدودًا بذلك، انتهاك حقوق الطبع والنشر، انتهاك العلامات التجارية، التشهير، انتهاك الخصوصية، سرقة الهوية، القرصنة، الكسر أو توزيع برمجيات مقرصنة؛',
        'terms_prohibited_activities_10' => 'إجراء أي تغييرات و/أو التدخل بأي شكل في كود مصدر الموقع وتحميل أي برمجيات و/أو تطبيقات قد تسبب ضررًا أو تلفًا للموقع أو أي طرف ثالث آخر؛',
        'terms_prohibited_activities_11' => 'تفكيك أو فك ترميز أو عكس هندسة أي برمجيات أو تقنية أخرى مدرجة في الموقع أو مستخدمة لتقديم الخدمات.',
        'terms_prohibited_activities_12' => 'تقر بأنه دون الإخلال بأي حق آخر قد نملكه، في حال ثبت أن استخدامك للموقع لا يتوافق مع أحكام هذه الشروط أو أي قانون ساري، يجوز لنا حظر وصولك إلى الموقع و/أو الخدمات.',
        'terms_intellectual_property_title' => '6. حقوق الملكية الفكرية',
        'terms_intellectual_property_1' => 'محتوى الموقع وميزاته، بما في ذلك المواد المرئية، النصوص، الصور، الشعارات، التصاميم، الموسيقى، الأصوات، الأشكال، العلامات التجارية وأي محتوى آخر مدمج في الموقع محمي بحقوق الملكية الفكرية الخاصة بنا أو لطرف ثالث.',
        'terms_intellectual_property_2' => 'بيننا وبين المستخدم، نحتفظ بجميع الحقوق والملكية والمصلحة في الموقع والخدمات. استخدام الموقع و/أو الخدمات لا يمنح المستخدم أيًا من حقوق الملكية الفكرية المدمجة في الموقع و/أو الخدمات، باستثناء الحق في استخدام الموقع و/أو الخدمات وفقًا لشروط هذه الشروط.',
        'terms_intellectual_property_3' => 'يجوز للمستخدم استخدام الموقع و/أو الخدمات للاستخدام الشخصي وغير التجاري فقط.',
        'terms_intellectual_property_4' => 'لا يجوز لك، ولا يجوز لك السماح لأي طرف آخر بتعديل أو فك ترميز أو تفكيك أو عكس هندسة أو نسخ أو نقل أو إنشاء أعمال مشتقة من أو تأجير أو منح ترخيص فرعي أو توزيع أو إعادة إنتاج أو إطار أو إعادة نشر أو كشط أو تنزيل أو عرض أو نقل أو نشر أو تأجير أو بيع بأي شكل أو بأي وسيلة، كليًا أو جزئيًا، استخدام لأي غرض آخر غير استخدام الموقع أو الخدمات وفقًا للشروط أو استغلال أي من محتويات الموقع بدون إذننا الكتابي الصريح المسبق.',
        'terms_liability_title' => '7. تحديد المسؤولية',
        'terms_liability_1' => 'لا يمكن تحميلنا المسؤولية عن الخسارة أو الضرر الناتج عن عدم الأداء أو الأداء غير السليم لهذه الشروط والذي يُنسب إلى (i) أنت أو (ii) الفعل غير القابل للتوقع والتغلب عليه من طرف ثالث للاتفاق أو (iii) حدث قوة قاهرة.',
        'terms_liability_2' => 'لا شيء في هذه الشروط يهدف إلى استبعاد أو تقييد مسؤوليتنا تجاهك حيث سيكون ذلك غير قانوني، لا سيما في حالة:',
        'terms_liability_3' => '(i) الوفاة أو الإصابة الشخصية الناتجة عن إهمالنا،',
        'terms_liability_4' => '(ii) الاحتيال أو التضليل الاحتيالي، و',
        'terms_liability_5' => '(iii) أي مسؤولية أخرى لا يمكن استبعادها أو تقييدها بموجب القانون السعودي.',
        'terms_liability_6' => 'دون الإخلال بعمومية ما سبق، لا نفترض أي مسؤولية أو التزام عن أي أخطاء، فيروسات، أحصنة طروادة، أو ما شابه قد تنتقل إلى أو من خلال الموقع أو الخدمات من قبل أي طرف ثالث، ما لم نكن مذنبين.',
        'terms_liability_7' => 'نبذل قصارى جهدنا للتأكد من أن الموقع خالٍ من الأخطاء أو الأخطاء أو عدم الدقة في أي محتوى. في حال حدوث مثل هذه الأخطاء أو الأخطاء أو عدم الدقة، سنعالجها دون تأخير.',
        'terms_liability_8' => 'توافق على تعويضنا عن أي خسائر تُسبب لأي طرف ثالث آخر، فيما يتعلق بالموقع و/أو الخدمات والناتجة عن انتهاكك لهذه الشروط.',
        'terms_liability_9' => 'لا نتحمل مسؤولية أي مشاكل أو عطل فني في أي خطوط هاتف أو شبكة، أنظمة حاسوبية عبر الإنترنت، خوادم أو مزودين، أجهزة، برمجيات، فشل بسبب مشاكل فنية أو ازدحام مرور على الإنترنت (أو عدم توفر الإنترنت) أو عدم توافق بين الموقع أو الخدمات ومتصفحك و/أو معداتك الأخرى. دون الإخلال بعمومية ما سبق، لا نفترض أي مسؤولية أو مخاطر عن استخدامك للإنترنت.',
        'terms_third_party_title' => '8. خدمات أو محتوى طرف ثالث',
        'terms_third_party_1' => 'أثناء استخدام الخدمات، قد تشاهد محتوى أو خدمات مقدمة من أطراف ثالثة، بما في ذلك الإعلانات والمراجعات المتعلقة بمنصات الطرف الثالث.',
        'terms_third_party_2' => 'لا نتحكم في أو نؤيد أو نتبنى مثل هذا المحتوى أو الخدمات، وقد لا تكون دائمًا دقيقة أو محدثة.',
        'terms_third_party_3' => 'وبالتالي، نوصي بالتحقق بشكل مستقل من جميع المعلومات قبل الاعتماد عليها، وأي قرارات أو إجراءات تُتخذ بناءً على مثل هذه المعلومات هي مسؤوليتك الوحيدة.',
        'terms_links_title' => '9. الروابط',
        'terms_links_1' => 'قد يحتوي الموقع على روابط أو محتوى أو إعلانات أو عروض ترويجية أو شعارات ومواد أخرى لمواقع ويب أو برمجيات أخرى يتم التحكم فيها أو تقديمها من قبل أطراف ثالثة (الروابط). نحذرك من التأكد من فهمك للمخاطر المرتبطة باستخدام مثل هذه المواقع أو البرمجيات أو المواد قبل استرجاع أو استخدام أو الاعتماد على أو شراء أي شيء عبر هذه المواقع أو البرمجيات، أو بناءً على مثل هذه المواد. يتم توفير هذه الروابط فقط لراحتك، وتوافق على أنه في أي حال لن تتحملنا المسؤولية عن أي خسارة أو ضرر ناتج عن استخدام أو الاعتماد على أي محتوى أو سلع أو خدمات متاحة على مواقع ويب أخرى.',
        'terms_links_2' => 'إدراج الروابط في الموقع لا يعني موافقتنا أو تفويضنا أو رعايتنا أو انتمائنا أو أي ارتباط آخر بيننا وبين هذه المواقع أو البرمجيات أو مشغليها.',
        'terms_links_3' => 'لم نراجع أيًا أو كل هذه الروابط ولن نتحمل مسؤولية أي محتوى للمواقع أو البرمجيات المشار إليها بها. نحذرك من التأكد من فهمك للمخاطر المرتبطة باستخدام مثل هذه المواقع أو البرمجيات قبل استرجاع أو استخدام أو الاعتماد على أو شراء أي شيء عبر هذه المواقع أو البرمجيات. في أي حال لن تتحملنا المسؤولية عن أي خسارة أو ضرر ناتج عن استخدام أو الاعتماد على أي محتوى أو سلع أو خدمات متاحة على مواقع ويب أخرى.',
        'terms_links_4' => 'تقع على عاتقك مسؤولية مراجعة شروط وسياسات مثل هذه المواقع الإلكترونية للطرف الثالث، ونوصي بشدة بمراجعتها بعناية قبل التفاعل مع مثل هذه الأطراف الثالثة.',
        'terms_miscellaneous_title' => '10. متفرقات',
        'terms_miscellaneous_1' => 'يجوز لنا تعديل أو إيقاف أو إنهاء أي من الخدمات و/أو تقديم خدمات جديدة من وقت لآخر مع أثر مستقبلي.',
        'terms_miscellaneous_2' => 'يجوز لنا تعديل هذه الشروط من وقت لآخر. عندما نفعل ذلك، سنقدم إشعارًا لك بنشر النسخة الأحدث ومراجعة التاريخ أعلى هذه الصفحة وأي تعديلات ستكون فعالة فورًا بعد هذا النشر. باستمرار استخدام الموقع بعد دخول أي تغييرات حيز التنفيذ، يُعتبر موافقتك على الشروط المعدلة.',
        'terms_miscellaneous_3' => 'يوافق المستخدم على أن نقل المعلومات إلى أو من الموقع لا ينشئ بين الطرفين أي علاقة تختلف عن تلك المحددة في هذه الشروط.',
        'terms_miscellaneous_4' => 'تشكل هذه الشروط وسياسة الخصوصية، كما يتم تعديلها من وقت لآخر، الاتفاقات الوحيدة الصالحة بيننا وبين المستخدم، ولا تكون أي تمثيل أو وعد أو موافقة أو تعهد، سواء كتابي أو شفهي، غير مدرج في الشروط أو سياسة الخصوصية ملزمًا للأطراف.',
        'terms_miscellaneous_5' => 'لا يشكل أي فشل أو تأخير من جانبنا في ممارسة أي حق أو سلطة أو تعويض بموجب هذه الشروط تنازلاً عنه، كما لا يمنع أي ممارسة فردية أو جزئية لهذا الحق أو السلطة أو التعويض أي ممارسة أخرى أو إضافية له أو ممارسة أي حق أو سلطة أو تعويض آخر.',
        'terms_miscellaneous_6' => 'إذا اعتبرت أي حكم من هذه الشروط من قبل محكمة ذات اختصاص قضائي غير قابل للتنفيذ بموجب القانون السارٍ، فسيتم استبعاد هذا الحكم من هذه الشروط وسيتم تفسير باقي الشروط كما لو تم استبعاد هذا الحكم وسيكون قابلاً للتنفيذ وفقًا لشروطه؛ ومع ذلك، في مثل هذه الحالة، يجب تفسير هذه الشروط بحيث يتم إعطاء أكبر قدر ممكن من الأثر المتوافق مع القانون السارٍ والمسموح به، لمعنى ونية الحكم المستبعد كما حددته محكمة الاختصاص القضائي المختصة.',
        'terms_miscellaneous_7' => 'يجوز لنا نقل أو التنازل عن أي وجميع حقوقنا والتزاماتنا بموجب هذه الشروط لأي طرف ثالث شريطة ألا يؤثر ذلك سلبًا على حقوقك. علاوة على ذلك، دون الإخلال بما سبق، يجوز تشغيل الموقع و/أو أي من الخدمات من قبل أطراف ثالثة. لا يجوز لك نقل أو التنازل أو التعهد بأي شكل من الأشكال عن أي من حقوقك أو التزاماتك بموجب هذه الشروط.',
        'terms_miscellaneous_8' => 'تخضع هذه الشروط للقانون السعودي.',
        'terms_miscellaneous_9' => 'يكون المكان الحصري للاختصاص القضائي لجميع النزاعات الناشئة عن أو فيما يتعلق بهذه الشروط هو محاكم الرياض.',
        'privacy_purpose_title' => 'غرض الإشعار',
        'privacy_purpose_text' => 'يهدف غرض هذا الإشعار بخصوص خصوصية البيانات (الإشعار) إلى شرح كيفية معالجة Floventra ("Floventra" أو "نحن" أو "لنا")، بصفتنا مراقب بيانات، لبياناتك الشخصية التي تقدمها لنا عند زيارتك لموقع floventus.com (الموقع)، أو التي نتلقاها من أطراف ثالثة، من أجل وضعك على اتصال بمحترفين قد يهمك.',
        'privacy_data_categories_title' => 'ما هي فئات البيانات الشخصية التي سيتم معالجتها؟',
        'privacy_data_categories_text' => 'نجمع ونعالج الفئات التالية من البيانات الشخصية عنك:',
        'privacy_data_collection_title' => 'كيف يتم جمع بياناتك؟',
        'privacy_data_collection_text' => 'سنجمع بياناتك الشخصية:',
        'privacy_data_collection_direct' => 'مباشرة منك، عندما تقدم بيانات التعريف الخاصة بك على موقعنا؛ و/أو',
        'privacy_data_collection_indirect' => 'بشكل غير مباشر:',
        'privacy_data_collection_indirect_1' => 'عندما نتلقى بيانات تعريف عنك من أطراف ثالثة (بما في ذلك شركات تعليم استثماري، شركاء / منتسبين / مسوقين / وكالات رقمية)؛ و/أو',
        'privacy_data_collection_indirect_2' => 'عندما نجمع بيانات متعلقة بتصفحك لموقعنا من خلال استخدام ملفات تعريف الارتباط أو تقنيات مماثلة (كما هو محدد في سياسة ملفات تعريف الارتباط).',
        'privacy_data_collection_note' => 'لست ملزمًا بتقديم بياناتك الشخصية لنا. ومع ذلك، عدم تقديم بياناتك الشخصية سيمنعنا من وضعك على اتصال بمحترفين قد يهمك.',
        'privacy_data_sharing_title' => 'مع من سيتم مشاركة بياناتي الشخصية؟',
        'privacy_data_sharing_text' => 'سنشارك بياناتك الشخصية:',
        'privacy_data_sharing_1' => 'داخل مجموعتنا؛',
        'privacy_data_sharing_2' => 'مع شركائنا، لأغراض معالجتهم الخاصة، بما في ذلك لتزويدك بمعلومات عن خدماتهم و/أو منتجاتهم التي قد تهمك، شريطة أن تكون قد أعطيت موافقتك المسبقة على هذه المشاركة. تشمل هذه الشركاء شركات تعليم استثماري مرخصة، وسطاء بيانات ووسطاء؛',
        'privacy_data_sharing_3' => 'مع أطراف ثالثة تقدم لنا خدمات مثل مزودي التخزين والاستضافة، الخدمات التحليلية والتقنية والتشخيصية؛',
        'privacy_data_sharing_4' => 'مع مستشارينا، لا سيما للامتثال لالتزاماتنا القانونية، خاصة فيما يتعلق بالمحاسبة والتدقيق والرقابة الداخلية؛',
        'privacy_data_sharing_5' => 'كجزء من بيع كل أو جزء من شركتنا وأصولها لطرف ثالث أو كجزء من إعادة تنظيم أو إعادة هيكلة أعمال (بما في ذلك الحل أو التصفية)؛ و',
        'privacy_data_sharing_6' => 'حيث يتطلب القانون أو يسمح به، للسلطات الحكومية والمحاكم والمستشارين الخارجيين وأطراف ثالثة مماثلة.',
        'privacy_cross_border_title' => 'نقل البيانات عبر الحدود',
        'privacy_cross_border_text_1' => 'ننقل بياناتك الشخصية خارج السعودية. بعض المتلقين موجودون في دول أصدر فيها الجهات السعودية قرارات بالكفاية، مثل الإمارات العربية المتحدة. يُعتبر النقل بالتالي معترفًا به كموفر لمستوى كافٍ من حماية البيانات من منظور القانون السعودي.',
        'privacy_cross_border_text_2' => 'قد يوجد بعض متلقي بياناتك الشخصية في بلد آخر لم يصدر فيه الجهات السعودية قرارات بالكفاية.',
        'privacy_cross_border_text_3' => 'من خلال إبرام اتفاقيات نقل بيانات مناسبة بناءً على البنود التعاقدية القياسية للقانون السعودي أو وسائل كافية أخرى، أثبتنا أن جميع المتلقين الآخرين الموجودين خارج السعودية سيوفرون مستوى كافٍ من حماية البيانات الشخصية وأن تدابير الأمان التقنية والتنظيمية المناسبة موجودة لحماية البيانات الشخصية من التدمير العرضي أو غير القانوني، الفقدان العرضي أو التغيير، الكشف أو الوصول غير المصرح به، وضد جميع الأشكال غير القانونية الأخرى للمعالجة. أي نقل لاحق (بما في ذلك الشركات التابعة لنا خارج السعودية) يخضع لمتطلبات النقل اللاحق المناسبة كما يتطلب القانون الساري.',
        'privacy_retention_title' => 'الاحتفاظ',
        'privacy_retention_text' => 'سنحتفظ بالبيانات الشخصية المجمعة فقط طالما كان ذلك ضروريًا بصرامة لتحقيق أغراض المعالجة المشار إليها في هذه الإشعار ووفقًا للقانون السعودي. عندما لم نعد بحاجة إلى استخدام بياناتك الشخصية، سيتم حذفها و/أو إخفاء هويتها بحيث لا يمكن تحديد الأفراد منها بعد (باستثناء الحد الذي يتطلب الاحتفاظ به للامتثال للالتزامات القانونية أو التنظيمية أو للدفاع أو ممارسة المطالبات القانونية).',
        'privacy_rights_title' => 'حقوقك',
        'privacy_rights_text' => 'بموجب القانون السعودي، لديك الحقوق التالية:',
        'privacy_right_access' => '<b>حق الوصول:</b> لديك الحق في الحصول منا على تأكيد ما إذا كانت البيانات الشخصية المتعلقة بك تُعالج أم لا، وفي حال كانت كذلك، طلب الوصول إلى البيانات الشخصية. تشمل معلومات الوصول - من بين أمور أخرى - أغراض المعالجة، فئات البيانات الشخصية المعنية، والمتلقين أو فئات المتلقين الذين تم أو سيتم الكشف عن البيانات الشخصية لهم. لديك الحق في الحصول على نسخة من البيانات الشخصية قيد المعالجة. مقابل نسخ إضافية طلبها منك، قد نتقاضى رسومًا معقولة بناءً على التكاليف الإدارية.',
        'privacy_right_rectification' => '<b>حق التصحيح:</b> لديك الحق في الحصول منا على تصحيح البيانات الشخصية غير الدقيقة المتعلقة بك. اعتمادًا على أغراض المعالجة، لديك الحق في إكمال البيانات الشخصية غير الكاملة، بما في ذلك من خلال تقديم بيان تكميلي.',
        'privacy_right_erasure' => '<b>حق الحذف (الحق في النسيان):</b> لديك الحق في طلب منا حذف بياناتك الشخصية.',
        'privacy_right_restriction' => '<b>حق تقييد المعالجة:</b> لديك الحق في طلب تقييد معالجة بياناتك الشخصية. في هذه الحالة، سيتم وضع علامة على البيانات المعنية ويمكن معالجتها من قبلنا لأغراض معينة فقط.',
        'privacy_right_portability' => '<b>حق نقل البيانات:</b> لديك الحق في استلام البيانات الشخصية المتعلقة بك التي قدمتها لنا بتنسيق منظم وشائع الاستخدام وقابل للقراءة آليًا ولديك الحق في نقل هذه البيانات الشخصية إلى كيان آخر دون عوائق من جانبنا.',
        'privacy_right_object' => '<b>حق الاعتراض:</b> لديك الحق في الاعتراض، لأسباب تتعلق بوضعك الخاص، في أي وقت على معالجة بياناتك الشخصية من قبلنا ويمكن أن نُطلب منا عدم معالجة بياناتك الشخصية بعد ذلك لهذه الأغراض. إذا كان لديك حق الاعتراض ومارسته، فلن تُعالج بياناتك الشخصية بعد ذلك لهذه الأغراض من جانبنا. ممارسة هذا الحق لن يترتب عليها أي تكاليف. قد لا يوجد مثل هذا الحق في الاعتراض، على وجه الخصوص، إذا كانت معالجة بياناتك الشخصية ضرورية لاتخاذ خطوات قبل الدخول في عقد أو لتنفيذ عقد تم إبرامه بالفعل.',
        'privacy_right_withdraw' => '<b>حق سحب موافقتك:</b> عندما يعتمد معالجة بياناتك الشخصية على موافقتك، لديك الحق في سحب موافقتك في أي وقت. مثل هذا الحق في سحب موافقتك لا يؤثر على مشروعية المعالجة المبنية على موافقتك التي قدمتها لنا سابقًا، قبل السحب.',
        'privacy_right_after_death' => '<b>حق بياناتك بعد وفاتك:</b> لديك الحق في إعطاء تعليمات متعلقة بالاحتفاظ بحذف والاتصال بالبيانات الشخصية التي تتعلق بك بعد وفاتك.',
        'privacy_rights_note' => 'يرجى ملاحظة أن هذه الحقوق قد تكون محدودة بموجب القانون السعودي لخصوصية البيانات المعمول به.',
        'privacy_rights_contact' => 'إذا كنت ترغب في ممارسة أي من هذه الحقوق، يرجى التواصل معنا كما هو موضح في قسم التواصل أدناه.',
        'privacy_rights_complaint' => 'لديك أيضًا الحق في تقديم شكوى إلى الجهة المختصة بحماية البيانات في السعودية، وهي هيئة حماية البيانات الشخصية.',
        'privacy_contact_title' => 'تواصل معنا',
        'privacy_contact_text' => 'الأفراد الذين لديهم أي أسئلة حول هذا الإشعار يجب أن يتواصلوا مع <a href="mailto:info@floventus.com">info@floventus.com</a>.',
        'privacy_changes_title' => 'التغييرات على إشعار الخصوصية',
        'privacy_changes_text' => 'هذا إشعار الخصوصية قابل للتغيير. سيتم إخطارك بشكل مناسب بأي تغييرات من هذا القبيل.',
        'privacy_last_updated' => 'آخر تحديث: 20.12.<script>document.write(new Date().getFullYear() - 2)</script>',
    ],
]
